# RISC-V toolchain path (from riscv-tools conda package)
export RISCV="${RISCV:-$CONDA_PREFIX/riscv-tools}"
export PATH="$RISCV/bin:$PATH"

# Compiler include paths (for emu compilation)
export CPLUS_INCLUDE_PATH="$CONDA_PREFIX/include:$CPLUS_INCLUDE_PATH"
export C_INCLUDE_PATH="$CONDA_PREFIX/include:$C_INCLUDE_PATH"

# Mill path (if installed in user directory)
if [ -f "$HOME/bin/mill" ]; then
    export PATH="$HOME/bin:$PATH"
fi

# <<< xs-env-vars <<<

# Fallback: if not modified by setup-conda.sh, use default paths
if [ -z "$XS_PROJECT_ROOT" ]; then
    export XS_PROJECT_ROOT=$(pwd)
    export NEMU_HOME=$(pwd)/NEMU
    export AM_HOME=$(pwd)/nexus-am
    export NOOP_HOME=$(pwd)/XiangShan
    export DRAMSIM3_HOME=$(pwd)/DRAMsim3
    export gem5_home=$(pwd)/gem5

    echo SET XS_PROJECT_ROOT: ${XS_PROJECT_ROOT}
    echo SET NOOP_HOME \(XiangShan RTL Home\): ${NOOP_HOME}
